    assert(slack?.urgency === "ok", "JSON SLACK_WEBHOOK urgency is 'ok'");
    assert(slack?.daysUntilExpiry === 174, "JSON SLACK_WEBHOOK daysUntilExpiry is 174");

    // Check sort order: expired, warning, ok
    assert(
      report.secrets[0].urgency === "expired" &&
